head.script:
scwin.flag = false;
scwin.editFlag = false;
scwin.columnNum = 17;

scwin.onpageload = function() {
    dma_searchCloseYm.set("coCd", "000");
    $c.sbm.execute(sbm_getMaxCloseYm);
};

scwin.f_CheckFileExt = function(ext, path) {
    ext = ext.toUpperCase();
    path = path.toUpperCase();
    let elen = ext.length;
    let flen = path.length;
    return (ext == path.substring((flen - elen), flen));
};

scwin.f_JobCloseYn = function(date) {
    date = date.substr(0, 6);
    if (dma_getMaxCloseYm.get("closeYm") > date) {
        return -1;
    } else if (dma_getMaxCloseYm.get("closeYm") < date) {
        return 0;
    } else {
        return 1;
    }
};

scwin.f_CsvValidation = async function() {
    if (ds_csv.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        return false;
    }

    let csvColCount = ds_csv.getColumnCount();
    if (csvColCount != scwin.columnNum) {
        await $c.gus.cfAlertMsg("\n컬럼값이 상이합니다. [형식=" + scwin.columnNum + "개] 입력한 열 개수 => " + csvColCount + "\n업로드 양식을 다운로드후, 양식에 맞게 입력해주세요.");
        return false;
    }

    let cntRow = ds_csv.getRowCount();

    for (let i = 0; i < ds_csv.getRowCount(); i++) {
        let colcnt = 0;
        for (let v = 0; v < ds_csv.getColumnCount(); v++) {
            let colId = ds_csv.getColumnID(v);
            if (ds_csv.getCellData(i, colId) == null || ds_csv.getCellData(i, colId) == '') {
                colcnt += 1;
            }
        }
        if (colcnt == scwin.columnNum) {
            cntRow = i;
            break;
        }

        let err = "";
        let partner = String(ds_csv.getCellData(i, ds_csv.getColumnID(2)) || "");
        if (partner == null) {
            partner = '';
            ds_csv.setCellData(i, ds_csv.getColumnID(2), '');
        }
        partner = partner.replace(/ /gi, "");
        let partnerYn = '';
        if (partner == 'Y' || partner == 'y') partnerYn = 'Y';
        else if (partner == "" || partner == null) partnerYn = 'N';
        else partnerYn = 'err';

        let customerCode = String(ds_csv.getCellData(i, ds_csv.getColumnID(5)) || "");
        if (customerCode == null) {
            customerCode = '';
            ds_csv.setCellData(i, ds_csv.getColumnID(5), '');
        }
        customerCode = customerCode.replace(/ /gi, "");
        let innerYn = false;
        if (customerCode == '109856' || customerCode == '내부' || customerCode == '내부거래' || customerCode.toUpperCase() == 'INTERNAL') {
            innerYn = true;
        }

        if (innerYn && partnerYn == 'Y') {
            err += "파트너인 경우, 내부거래 코드가 올 수 없습니다.";
        }

        for (let k = 0; k < ds_csv.getColumnCount(); k++) {
            let temp = String(ds_csv.getCellData(i, ds_csv.getColumnID(k)) || "");
            if (temp == null) {
                ds_csv.setCellData(i, ds_csv.getColumnID(k), '');
                temp = '';
            }
            temp = temp.replace(/ /gi, "");
            temp = temp.replace(/,/gi, "");
            temp = temp.toUpperCase();
            ds_csv.setCellData(i, ds_csv.getColumnID(k), temp);

            switch (k) {
                case 0:
                    if (temp == '' || !(/^[SA]{1}$/.test(temp))) {
                        err += "'SEA/AIR'열에는 S나 A를 입력해주세요. ";
                    }
                    break;
                case 1:
                    if (temp == '' || !(/^[IE]{1}$/.test(temp))) {
                        err += "'EXP/IMP'열에는 I나 E를 입력해주세요. ";
                    }
                    break;
                case 2:
                    if (partnerYn == 'err') {
                        err += "'파트너'열에는 파트너일 경우 Y, 아닐 경우 공백으로 입력해주세요. ";
                    }
                    break;
                case 3:
                    if ((partnerYn == 'Y' && !(/^[CD]{1}$/.test(temp))) || (partnerYn == 'N' && temp != '')) {
                        err += "'C/D'열에는 파트너일 경우 C나 D, 아닐 경우 공백으로 입력해주세요. ";
                    }
                    break;
                case 4:
                    if (temp == '') {
                        err += "House B/L을 입력해주세요. ";
                    }
                    break;
                case 5:
                    if (temp == '') {
                        err += "Customer Code를 입력해주세요. ";
                    }
                    break;
                case 6:
                    if (temp == '') {
                        err += "Freight Code를 입력해주세요. ";
                    } else if (innerYn && (temp.charAt(temp.length - 1) == 'V' || temp.charAt(temp.length - 1) == 'K')) {
                        err += "내부거래일 경우, 운임코드에 -V, -K의 코드는 올 수 없습니다. ";
                    } else if (partnerYn != 'Y' && ds_csv.getCellData(i, ds_csv.getColumnID(7)) != ''
                        && ds_csv.getCellData(i, ds_csv.getColumnID(7)) != 'KRW' && (ds_csv.getCellData(i, ds_csv.getColumnID(14)) == 'Y')) {
                        let c = temp.charAt(temp.length - 1);
                        if (c == 'J' || c == 'V' || c == 'K') {
                            err += "CUR이 KRW가 아니며 외화정산이 Y일 경우, 운임코드에 -J, -V, -K의 코드는 올 수 없습니다. ";
                        }
                    }
                    break;
                case 7:
                    if (temp == '') {
                        err += "CUR를 입력해주세요. ";
                    }
                    break;
                case 8:
                    if (isNaN(temp)) {
                        err += "'Amount'열은 숫자나 공백으로 입력해주세요. ";
                    }
                    break;
                case 9:
                    if (isNaN(temp)) {
                        err += "'Ex-rate'열은 숫자나 공백으로 입력해주세요. ";
                    }
                    break;
                case 10:
                    if (isNaN(temp)) {
                        err += "'Amount(원)'열은 숫자나 공백으로 입력해주세요. ";
                    }
                    break;
                case 11:
                    if (isNaN(temp)) {
                        err += "'VAT'열은 숫자나 공백으로 입력해주세요. ";
                    }
                    if (String(ds_csv.getCellData(i, ds_csv.getColumnID(6))).charAt(String(ds_csv.getCellData(i, ds_csv.getColumnID(6))).length - 1) == 'V') {
                        ds_csv.setCellData(i, ds_csv.getColumnID(11), ds_csv.getCellData(i, ds_csv.getColumnID(10)) * 0.1);
                    }
                    break;
                case 12:
                    if (temp == '' || isNaN(temp) || temp.length != 8) {
                        err += "'Result Date'열은 날짜로 입력해주세요. ";
                    } else if (scwin.f_JobCloseYn(temp) == -1) {
                        err += "'Result Date'의 날짜는 결산이 완료된 과거로 설정될 수 없습니다. ";
                    }
                    break;
                case 13:
                    break;
                case 14:
                    if (partnerYn == 'N' && (temp != '' && temp != 'Y')) {
                        err += "'외화 정산'열은 Y나 공백으로 입력해주세요. ";
                    }
                    break;
                case 15:
                    if (innerYn) {
                        if (temp == '') {
                            err += "내부거래 코드를 입력해주세요. ";
                        }
                    } else {
                        if (temp != '') {
                            err += "Customer Code가 '109856'일 경우에만 내부거래 코드를 입력할 수 있습니다. ";
                        }
                    }
                    break;
                case 16:
                    if (!innerYn) {
                        if (temp == '') {
                            err += "'요청범위'를 입력해주세요. (1~2) ";
                        } else if (temp != '1' && temp != '2') {
                            err += "'요청범위'는 1~2 사이의 숫자를 입력해주세요. ";
                        } else if (temp == '2') {
                            if (ds_csv.getCellData(i, ds_csv.getColumnID(13)) == '' || isNaN(ds_csv.getCellData(i, ds_csv.getColumnID(13))) || String(ds_csv.getCellData(i, ds_csv.getColumnID(13))).length != 8) {
                                err += "'Invoice Date'열은 날짜로 입력해주세요. ";
                            } else if (scwin.f_JobCloseYn(ds_csv.getCellData(i, ds_csv.getColumnID(13))) == -1) {
                                err += "'Invoice Date'의 날짜는 결산이 완료된 과거로 설정될 수 없습니다. ";
                            }
                        }
                    }
                    break;
            }
        }

        ds_err.insertRow(ds_err.getRowCount());
        ds_err.setCellData(ds_err.getRowCount() - 1, "err", err);
        if (err == '') {
            if (innerYn) {
                ds_csv.setCellData(i, ds_csv.getColumnID(5), '109856');
                ds_csv.setCellData(i, ds_csv.getColumnID(16), 0);
            }
            ds_RetrieveValidation.removeAll();
            ds_validation.removeAll();
            scwin._copyRowToDataList(ds_csv, i, ds_RetrieveValidation);
            await $c.sbm.execute(sbm_validation);
        }
    }

    scwin._copyDataListRange(ds_csv, 0, cntRow, ds_freightList);
    for (let k = 0; k < ds_freightList.getRowCount(); k++) {
        ds_freightList.setCellData(k, "err", ds_err.getCellData(k, "err"));
    }
    ds_err.removeAll();
    return true;
};

scwin._copyRowToDataList = function(srcDs, srcRow, tgtDs) {
    tgtDs.removeAll();
    tgtDs.insertRow(0);
    for (let c = 0; c < srcDs.getColumnCount(); c++) {
        let colId = srcDs.getColumnID(c);
        let tgtColIds = [];
        for (let tc = 0; tc < tgtDs.getColumnCount(); tc++) {
            tgtColIds.push(tgtDs.getColumnID(tc));
        }
        if (tgtColIds.indexOf(colId) > -1) {
            tgtDs.setCellData(0, colId, srcDs.getCellData(srcRow, colId));
        }
    }
};

scwin._copyDataListRange = function(srcDs, startRow, endRow, tgtDs) {
    tgtDs.removeAll();
    for (let i = startRow; i < endRow; i++) {
        tgtDs.insertRow(tgtDs.getRowCount());
        let tgtRow = tgtDs.getRowCount() - 1;
        for (let c = 0; c < srcDs.getColumnCount(); c++) {
            let colId = srcDs.getColumnID(c);
            let tgtColIds = [];
            for (let tc = 0; tc < tgtDs.getColumnCount(); tc++) {
                tgtColIds.push(tgtDs.getColumnID(tc));
            }
            if (tgtColIds.indexOf(colId) > -1) {
                tgtDs.setCellData(tgtRow, colId, srcDs.getCellData(i, colId));
            }
        }
    }
};

scwin._copyRowBetweenDataLists = function(srcDs, srcRow, tgtDs, tgtRow) {
    for (let c = 0; c < srcDs.getColumnCount(); c++) {
        let colId = srcDs.getColumnID(c);
        let tgtColIds = [];
        for (let tc = 0; tc < tgtDs.getColumnCount(); tc++) {
            tgtColIds.push(tgtDs.getColumnID(tc));
        }
        if (tgtColIds.indexOf(colId) > -1) {
            tgtDs.setCellData(tgtRow, colId, srcDs.getCellData(srcRow, colId));
        }
    }
};

scwin.drmFileSubmit = function() {
    // TODO: DRM 파일 업로드는 WebSquare 파일 업로드 컴포넌트로 대체 필요
    $c.gus.cfDrmUploadFile(null, null, "scwin.f_Upload");
};

scwin.f_Upload = function() {
    ds_csv.removeAll();
    // TODO: 파일 업로드 후 CSV 데이터를 ds_csv에 로드하는 로직은 WebSquare 파일 업로드 API로 대체 필요
    $c.gus.cfProgressWinOpen();
    window.setTimeout(function() { scwin.f_Import(); }, 1000);
};

scwin.f_Import = async function() {
    scwin.f_DsClear();
    scwin.flag = false;
    $c.gus.cfProgressWinClose();
    if (await scwin.f_CsvValidation()) {
        $c.gus.cfShowTotalRows(totalRows, ds_freightList.getRowCount());
        await $c.gus.cfAlertMsg("업로드 완료");
    } else {
        $c.gus.cfShowTotalRows(totalRows, 0);
    }
    scwin.f_ErrCheck();
};

scwin.f_ErrCheck = function() {
    for (let i = 0; i < ds_freightList.getRowCount(); i++) {
        if (ds_freightList.getCellData(i, "err") != "") {
            scwin.flag = false;
            return;
        }
    }
    scwin.flag = true;
    return;
};

scwin.btn_Save_onclick = function(e) {
    scwin.f_Save();
};

scwin.f_Save = async function() {
    if (scwin.editFlag) {
        await $c.gus.cfAlertMsg("수정한 값이 존재합니다. 재검증 버튼을 눌러 재검증을 해주세요.");
        return;
    }
    if (!ds_freightList.isUpdated()) {
        await $c.gus.cfAlertMsg("변경된 내역이 없습니다. 업로드 후 저장해주세요.");
        return;
    }
    if (!scwin.flag) {
        await $c.gus.cfAlertMsg("수정되지 않은 오류 내역이 있습니다. '오류'열을 확인하고, 수정 후 재업로드 해주세요.");
        return;
    }

    let chk = await $c.win.confirm("저장하시겠습니까?");
    if (!chk) {
        return;
    }

    for (let i = 0; i < ds_freightList.getRowCount(); i++) {
        ds_dbCodeRetrieve.removeAll();
        scwin._copyRowToDataList(ds_freightList, i, ds_dbCodeRetrieve);
        await $c.sbm.execute(sbm_dbCodeRetrieve);
    }

    for (let i = 0; i < ds_freightList.getRowCount(); i++) {
        let SA = ds_freightList.getCellData(i, "seaAirCls");
        let IE = ds_freightList.getCellData(i, "expImp");
        let P = ds_freightList.getCellData(i, "partner");

        let temp;
        let tempInv;
        if (SA == 'S') {
            if (IE == 'I') {
                if (P == 'Y') {
                    temp = ds_seaImpPartner;
                    tempInv = ds_invoiceSIP;
                } else {
                    temp = ds_seaImpBuying;
                    tempInv = ds_invoiceSIB;
                }
            } else {
                if (P == 'Y') {
                    temp = ds_seaExpPartner;
                    tempInv = ds_invoiceSEP;
                } else {
                    temp = ds_seaExpBuying;
                    tempInv = ds_invoiceSEB;
                }
            }
        } else {
            if (IE == 'I') {
                if (P == 'Y') {
                    temp = ds_airImpPartner;
                    tempInv = ds_invoiceAIP;
                } else {
                    temp = ds_airImpBuying;
                    tempInv = ds_invoiceAIB;
                }
            } else {
                if (P == 'Y') {
                    temp = ds_airExpPartner;
                    tempInv = ds_invoiceAEP;
                } else {
                    temp = ds_airExpBuying;
                    tempInv = ds_invoiceAEB;
                }
            }
        }

        temp.insertRow(temp.getRowCount());
        let tRow = temp.getRowCount() - 1;
        temp.setCellData(tRow, "odrNo", ds_dbCodeList.getCellData(i, "odrNo"));
        temp.setCellData(tRow, "kcomcd", ds_dbCodeList.getCellData(i, "kcomcd"));
        temp.setCellData(tRow, "seaAirCls", SA);
        temp.setCellData(tRow, "blNo", ds_freightList.getCellData(i, "blNo"));
        temp.setCellData(tRow, "mhno", ds_dbCodeList.getCellData(i, "mhno"));
        temp.setCellData(tRow, "fareEngCd", ds_freightList.getCellData(i, "freightCd"));
        temp.setCellData(tRow, "fareEngNm", ds_dbCodeList.getCellData(i, "fareEngNm"));
        temp.setCellData(tRow, "fareGrpCd", ds_dbCodeList.getCellData(i, "fareGrpCd"));
        temp.setCellData(tRow, "fareUnit", SA == 'S' ? 'CASE' : '');
        temp.setCellData(tRow, "locPtnCls", P == 'Y' ? '2' : '1');
        temp.setCellData(tRow, "mblHblCls", 'H');
        temp.setCellData(tRow, "drcrCls", P == 'Y' ? ds_freightList.getCellData(i, "cd") : 'C');
        temp.setCellData(tRow, "ppccCls", SA == 'S' ? ds_dbCodeList.getCellData(i, "ppccCls") : '');
        temp.setCellData(tRow, "crcCd", ds_freightList.getCellData(i, "crcCd"));
        temp.setCellData(tRow, "qty", SA == 'S' ? 0 : ds_dbCodeList.getCellData(i, "qty"));
        temp.setCellData(tRow, "grossWt", SA == 'S' ? 0.0 : ds_dbCodeList.getCellData(i, "grossWt"));
        temp.setCellData(tRow, "chgWt", 1);
        temp.setCellData(tRow, "trfUpr", 0.0);
        temp.setCellData(tRow, "exRate", ds_freightList.getCellData(i, "exRate"));
        temp.setCellData(tRow, "exRateTyp", SA == 'S' ? ds_dbCodeList.getCellData(i, "exRateTyp") : '');
        temp.setCellData(tRow, "prtnAmt", 0);
        temp.setCellData(tRow, "rsltsStdDt", ds_freightList.getCellData(i, "resultDate"));
        temp.setCellData(tRow, "vatYn", ds_freightList.getCellData(i, "vat") > 0 ? 1 : 0);

        if (P == 'Y') {
            temp.setCellData(tRow, "sellSeq", 0);
            temp.setCellData(tRow, "bilgClntNo", ds_freightList.getCellData(i, "custCd"));
            temp.setCellData(tRow, "bilgClntNm", ds_dbCodeList.getCellData(i, "bilgClntNm"));
            temp.setCellData(tRow, "sellItemCd", ds_dbCodeList.getCellData(i, "sellItemCd"));
            temp.setCellData(tRow, "sellUpr", 1);
            temp.setCellData(tRow, "sellAmtFcrc", ds_freightList.getCellData(i, "amount"));
            temp.setCellData(tRow, "sellAmt", ds_freightList.getCellData(i, "amountWon") != '' ?
                ds_freightList.getCellData(i, "amountWon") : (ds_freightList.getCellData(i, "amount") * ds_freightList.getCellData(i, "exRate")));
            temp.setCellData(tRow, "vatAmt", ds_freightList.getCellData(i, "vat"));
        } else {
            temp.setCellData(tRow, "pchsSeq", 0);
            temp.setCellData(tRow, "pchsClntNo", ds_freightList.getCellData(i, "custCd"));
            temp.setCellData(tRow, "pchsClntNm", ds_dbCodeList.getCellData(i, "pchsClntNm"));
            temp.setCellData(tRow, "selpchItemCd", ds_dbCodeList.getCellData(i, "selpchItemCd"));
            temp.setCellData(tRow, "pchsUpr", 1);
            temp.setCellData(tRow, "pchsAmtFcrc", ds_freightList.getCellData(i, "amount"));
            temp.setCellData(tRow, "pchsAmt", ds_freightList.getCellData(i, "amountWon") != '' ?
                ds_freightList.getCellData(i, "amountWon") : (ds_freightList.getCellData(i, "amount") * ds_freightList.getCellData(i, "exRate")));
            temp.setCellData(tRow, "vat", ds_freightList.getCellData(i, "vat"));
            temp.setCellData(tRow, "sellDeptCd", ds_freightList.getCellData(i, "innerDept") != '' ? ds_freightList.getCellData(i, "innerDept") : '');
            temp.setCellData(tRow, "sellDeptNm", ds_freightList.getCellData(i, "innerDept") != '' ? ds_dbCodeList.getCellData(i, "sellDeptNm") : '');
            temp.setCellData(tRow, "pchsTyp", ds_freightList.getCellData(i, "innerDept") != '' ? '3' : '1');
        }

        if (SA == 'S' && ds_dbCodeList.getCellData(i, "usdAmt") != 0) {
            temp.setCellData(tRow, "usdAmt", P == 'Y' ?
                Math.round((temp.getCellData(tRow, "sellAmt") / ds_dbCodeList.getCellData(i, "usdAmt")) * 100) / 100
                : Math.round((temp.getCellData(tRow, "pchsAmt") / ds_dbCodeList.getCellData(i, "usdAmt")) * 100) / 100);
        }

        if (SA == 'A' && IE == 'E' && P == 'Y') {
            temp.setCellData(tRow, "qty", 0);
            temp.setCellData(tRow, "grossWt", 0);
        }

        tempInv.insertRow(tempInv.getRowCount());
        let invRow = tempInv.getRowCount() - 1;
        scwin._copyRowBetweenDataLists(temp, tRow, tempInv, invRow);
        tempInv.setCellData(invRow, "billingDate", ds_freightList.getCellData(i, "billingDate"));
        tempInv.setCellData(invRow, "foreignCurSet", ds_freightList.getCellData(i, "foreignCurSet"));
        tempInv.setCellData(invRow, "requestSize", ds_freightList.getCellData(i, "requestSize"));
        tempInv.setCellData(invRow, "partner", P);
        tempInv.setCellData(invRow, "expImp", IE == 'I' ? 'I' : 'O');
    }

    await $c.sbm.execute(sbm_saveFreight);
};

scwin.f_tmp = function() {
    let tmp = "확인 \n\n";
    let check = ds_seaImpPartner;
    for (let i = 0; i < check.getRowCount(); i++) {
        for (let j = 0; j < check.getColumnCount(); j++) {
            tmp = tmp + check.getCellData(i, check.getColumnID(j)) + ", ";
        }
        tmp = tmp + "\n";
    }
    alert(tmp);

    let cnt = "열 수 확인 \n" + ds_seaImpPartner.getRowCount() + "\n" + ds_seaImpBuying.getRowCount() + "\n"
        + ds_seaExpPartner.getRowCount() + "\n" + ds_seaExpBuying.getRowCount() + "\n"
        + ds_airImpPartner.getRowCount() + "\n" + ds_airImpBuying.getRowCount() + "\n"
        + ds_airExpPartner.getRowCount() + "\n" + ds_airExpBuying.getRowCount() + "\n";
    alert(cnt);
};

scwin.f_DsClear = function() {
    ds_freightList.removeAll();
    ds_RetrieveValidation.removeAll();
    ds_validation.removeAll();
    ds_err.removeAll();
    ds_seaImpPartner.removeAll();
    ds_seaImpBuying.removeAll();
    ds_seaExpPartner.removeAll();
    ds_seaExpBuying.removeAll();
    ds_airImpPartner.removeAll();
    ds_airImpBuying.removeAll();
    ds_airExpPartner.removeAll();
    ds_airExpBuying.removeAll();
    ds_dbCodeList.removeAll();
    ds_dbCodeRetrieve.removeAll();
    ds_dbCodeResult.removeAll();
    ds_invoiceSIP.removeAll();
    ds_invoiceSIB.removeAll();
    ds_invoiceSEP.removeAll();
    ds_invoiceSEB.removeAll();
    ds_invoiceAIP.removeAll();
    ds_invoiceAIB.removeAll();
    ds_invoiceAEP.removeAll();
    ds_invoiceAEB.removeAll();
    $c.gus.cfShowTotalRows(totalRows, 0);
};

scwin.btn_ReCheck_onclick = function(e) {
    scwin.f_ReCheck();
};

scwin.f_ReCheck = async function() {
    if (!scwin.editFlag) {
        await $c.gus.cfAlertMsg("값을 수정 후, 재검증 버튼을 눌러주세요.");
        return;
    }
    if (ds_freightList.getRowCount() == 0) {
        await $c.gus.cfAlertMsg("먼저 CSV 파일을 업로드해주세요.");
        return;
    }
    ds_csv.removeAll();
    scwin._copyDataListRange(ds_freightList, 0, ds_freightList.getRowCount(), ds_csv);
    ds_freightList.removeAll();
    ds_err.removeAll();

    if (await scwin.f_CsvValidation()) {
        scwin.f_ErrCheck();
        await $c.gus.cfAlertMsg("재검사를 완료하였습니다.");
    }
    scwin.editFlag = false;
};

scwin.sbm_validation_submitdone = function(e) {
    let arr = ["blNo", "custCd", "freightCd", "crcCd", "innerDept"];
    let arrMsg = ["House B/L", "Customer Code", "Freight Code", "CUR Code", "내부거래 코드"];

    let msg = "";
    for (let i = 0; i < arr.length; i++) {
        if (ds_validation.getCellData(0, arr[i]) != '1') {
            msg += arrMsg[i] + " 항목이 유효하지 않습니다. ";
        }
    }
    ds_err.setCellData(ds_err.getRowCount() - 1, "err", ds_err.getCellData(ds_err.getRowCount() - 1, "err") + msg);
};

scwin.sbm_validation_submiterror = function(e) {
    $c.gus.cfShowError(e);
    scwin.f_DsClear();
    ds_csv.removeAll();
};

