scwin.gr_freightList_complete_oncelldblclick = function(rowIndex, columnIndex, columnId) {
    if (rowIndex > -1) {
        if (ds_freightList_complete.getCellData(rowIndex, "seaAirCls") == "S") {
            if (ds_freightList_complete.getCellData(rowIndex, "expImp") == "I") {
                let param = {
                    linkcheck: "2",
                    kcomcd: "DBEX",
                    blno: ds_freightList_complete.getCellData(rowIndex, "blNo")
                };
                $c.win.openMenu("Import House B/L (New)", "/ui/il/seainb/sibl/se_201_01_03b.xml", "se_201_01_03b.xml", param);
            } else {
                let param = {
                    linkcheck: "2",
                    kcomcd: "DBEX",
                    blno: ds_freightList_complete.getCellData(rowIndex, "blNo")
                };
                $c.win.openMenu("Export House B/L (New)", "/ui/il/seaout/sobl/se_105_01_05b.xml", "se_105_01_05b.xml", param);
            }
        } else {
            if (ds_freightList_complete.getCellData(rowIndex, "expImp") == "I") {
                let param = {
                    kcomcd: "DBEX",
                    blno: ds_freightList_complete.getCellData(rowIndex, "blNo")
                };
                $c.win.openMenu("Import House B/L (New)", "/ui/il/airinb/aibl/ar_203_01_03b.xml", "ar_203_01_03b.xml", param);
            } else {
                let param = {
                    kcomcd: "DBEX",
                    blno: ds_freightList_complete.getCellData(rowIndex, "blNo")
                };
                $c.win.openMenu("Export House B/L (New)", "/ui/il/airout/aobl/ar_104_01_06b.xml", "ar_104_01_06b.xml", param);
            }
        }
    }
};
